const ActivityItem: React.FC<{ item: CallRecord, isEven: boolean }> = ({ item, isEven }) => {
  const [hoverPos, setHoverPos] = useState({ x: 0, y: 0 });
  const [hoverType, setHoverType] = useState<'summary' | 'emotion' | null>(null);

  const handleMouseMove = (e: React.MouseEvent) => {
    // Only update for tooltip positioning
    if (hoverType) {
        setHoverPos({ x: e.clientX, y: e.clientY });
    }
  };

  const getSentimentColor = () => {
    switch (item.flags.sentiment) {
      case 'positive': return 'bg-emerald-500';
      case 'negative': return 'bg-amber-500';
      case 'angry': return 'bg-rose-600';
      default: return 'bg-slate-300';
    }
  };

  const getDirectionIcon = () => {
    if (item.type === 'message') {
        return item.direction === 'inbound' 
            ? <MessageSquare size={13} className="text-indigo-600 fill-indigo-50" /> 
            : <MessageSquare size={13} className="text-slate-400" />;
    }
    switch (item.direction) {
      case 'inbound': return <ArrowDownLeft size={14} strokeWidth={2.5} className="text-emerald-600" />;
      case 'outbound': return <ArrowUpRight size={14} strokeWidth={2.5} className="text-blue-600" />;
      case 'missed': return <PhoneMissed size={14} strokeWidth={2.5} className="text-rose-600" />;
    }
  };

  return (
    <div 
        className={`group relative py-2 border-b border-slate-200 flex items-center text-[11px] hover:bg-slate-50 transition-colors ${isEven ? 'bg-white' : 'bg-slate-50/30'}`}
        onMouseMove={handleMouseMove}
    >
      {/* Sentiment Indicator (Left Border) */}
      <div className={`absolute left-0 top-0 bottom-0 w-[3px] ${getSentimentColor()} opacity-80`}></div>

      {/* Time */}
      <div className="w-[72px] pl-3 font-medium text-slate-600 tabular-nums tracking-tight whitespace-nowrap flex-shrink-0 group-hover:text-slate-900">
        {item.timestamp}
      </div>

      {/* Source Icon */}
      <div className="w-8 flex justify-center text-slate-400 flex-shrink-0">
          {item.isBot ? <Bot size={16} className="text-emerald-600" /> : <Monitor size={14} strokeWidth={1.5} />}
      </div>

      {/* Contact Info */}
      <div 
        className="flex-1 min-w-0 flex flex-col justify-center px-1 cursor-pointer"
        onMouseEnter={() => setHoverType('summary')}
