const ActionButton: React.FC<{ icon: any, label: string, color: string }> = ({ icon: Icon, label, color }) => {
    // Dynamic styles map based on color input, handling both theme colors and fixed colors
    const getColorClass = (c: string) => {
         if (['emerald', 'blue', 'violet', 'purple', 'rose', 'slate'].includes(c)) {
             return `bg-${c}-50 text-${c}-600 border-${c}-100 hover:bg-${c}-100`;
         }
         return 'bg-slate-50 text-slate-600 border-slate-200 hover:bg-slate-100';
    }

    return (
        <button className={`flex flex-col items-center justify-center gap-1 p-2 rounded-lg border transition-all hover:scale-[1.02] active:scale-95 ${getColorClass(color)}`}>
            <Icon size={18} />
            <span className="text-[10px] font-bold">{label}</span>
        </button>
    )
}

const HollowSentimentIcon: React.FC<{ sentiment: string }> = ({ sentiment }) => {
    const { primaryColor } = useTheme();
    switch(sentiment) {
        case 'positive': return <Smile size={20} strokeWidth={2} className={`text-${primaryColor}-500`} />;
        case 'negative': return <Frown size={20} strokeWidth={2} className="text-amber-500" />;
        case 'angry': return <OctagonAlert size={20} strokeWidth={2} className="text-rose-600" />;
